    }

    // Directions: Up, Down, Left, Right
    val dr = arrayOf(-1L, 1L, 0L, 0L)
    val dc = arrayOf(0L, 0L, -1L, 1L)

    // 2. Dijkstra/Multi-source BFS simulation
    while (pq.isNotEmpty()) {
        val current = pq.poll()
        val t = current.time
        val c = -current.negColor
        val r = current.r
        val c_coord = current.c

        // Check for stale entries using the stored distance
        val storedDist = dist[r.toInt()][c_coord.toInt()]

